const items = $input.all();

function extractJson(value) {
  if (typeof value === "object" && value !== null) return value;
  if (!value) return null;

  const text = String(value).trim();

  try {
    return JSON.parse(text);
  } catch (e) {
    const match = text.match(/\{[\s\S]*\}/);
    if (!match) return null;

    try {
      return JSON.parse(match[0]);
    } catch (e2) {
      return null;
    }
  }
}

function normalizeConfidence(value) {
  const number = Number(value || 0);
  if (number <= 1) return Math.round(number * 100);
  return Math.round(number);
}

const output = [];

for (const item of items) {
  const raw = item.json.output || item.json.text || item.json.response || item.json;
  const parsed = extractJson(raw);

  if (!parsed) {
    output.push({
      json: {
        decision_valid: false,
        error_type: "FINAL_DECISION_PARSE_ERROR",
        error_message: "Sortie Decision Synthesizer invalide ou non JSON",
        final_summary: "FlowMind a détecté des risques, mais la synthèse IA doit être vérifiée manuellement.",
        global_risk_level: "À vérifier",
        sprint_failure_probability: 0,
        critical_decision: false,
        ai_data_quality: {
          complete: false,
          failed_agents: ["Decision Synthesizer"],
          warning: "Sortie non JSON"
        },
        decisions_today: [],
        review_actions: [],
        scope_actions: [],
        escalations: [],
        notification_required: true,
        notification_target: "ops",
        slack_message: "FlowMind : la synthèse IA finale est invalide. Vérification manuelle requise.",
        confidence_score: 0,
        raw_output: raw,
        created_at: new Date().toISOString()
      }
    });
    continue;
  }

  output.push({
    json: {
      decision_valid: true,
      final_summary: parsed.final_summary || "",
      global_risk_level: parsed.global_risk_level || "",
      sprint_failure_probability: Number(parsed.sprint_failure_probability || 0),
      critical_decision: parsed.critical_decision === true,

      ai_data_quality: parsed.ai_data_quality || {
        complete: true,
        failed_agents: [],
        warning: ""
      },

      decisions_today: parsed.decisions_today || [],
      review_actions: parsed.review_actions || [],
      scope_actions: parsed.scope_actions || [],
      escalations: parsed.escalations || [],

      notification_required: parsed.notification_required === true,
      notification_target: parsed.notification_target || "",
      slack_message: parsed.slack_message || "",
      confidence_score: normalizeConfidence(parsed.confidence_score),

      final_decision_output: parsed,
      created_at: new Date().toISOString()
    }
  });
}

return output;

const items = $input.all();
const risks = items.map(item => item.json);

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function groupBy(array, field) {
  const result = {};
  for (const item of array) {
    const key = clean(item[field]) || "Non qualifié";
    if (!result[key]) result[key] = [];
    result[key].push(item);
  }
  return result;
}

const totalRisks = risks.length;
const criticalRisks = risks.filter(r => r.risk_level === "Critique");
const highRisks = risks.filter(r => r.risk_level === "Élevé");
const mediumRisks = risks.filter(r => r.risk_level === "Moyen");

const validationRisks = risks.filter(r =>
  clean(r.risk_type).toLowerCase().includes("validation")
);

const technicalRisks = risks.filter(r =>
  clean(r.risk_type).toLowerCase().includes("technique")
);

const noOwnerRisks = risks.filter(r =>
  !clean(r.assignee) ||
  clean(r.reasons_detected).toLowerCase().includes("aucun responsable")
);

const risksByAssignee = groupBy(risks, "assignee");
const risksByType = groupBy(risks, "risk_type");
const risksBySource = groupBy(risks, "source");

const sprintHealthScore = risks[0]?.sprint_health_score ?? 100;
const globalRiskLevel = risks[0]?.global_risk_level ?? "Faible";
const executiveSummary = risks[0]?.executive_summary ?? "";

let estimatedFailureProbability = 0;

if (sprintHealthScore >= 80) estimatedFailureProbability = 15;
else if (sprintHealthScore >= 60) estimatedFailureProbability = 35;
else if (sprintHealthScore >= 40) estimatedFailureProbability = 60;
else estimatedFailureProbability = 80;

estimatedFailureProbability += criticalRisks.length * 5;
estimatedFailureProbability += highRisks.length * 3;
estimatedFailureProbability += validationRisks.length * 2;

if (estimatedFailureProbability > 95) estimatedFailureProbability = 95;

const topRisks = risks
  .sort((a, b) => Number(b.risk_score || 0) - Number(a.risk_score || 0))
  .slice(0, 10);

return [
  {
    json: {
      project_context: {
        sprint_health_score: sprintHealthScore,
        global_risk_level: globalRiskLevel,
        estimated_failure_probability: estimatedFailureProbability,
        executive_summary: executiveSummary
      },

      risk_summary: {
        total_risks: totalRisks,
        critical_risks: criticalRisks.length,
        high_risks: highRisks.length,
        medium_risks: mediumRisks.length,
        validation_risks: validationRisks.length,
        technical_risks: technicalRisks.length,
        no_owner_risks: noOwnerRisks.length
      },

      top_risks: topRisks,

      grouped_insights: {
        risks_by_assignee: Object.keys(risksByAssignee).map(name => ({
          assignee: name,
          count: risksByAssignee[name].length
        })),
        risks_by_type: Object.keys(risksByType).map(type => ({
          risk_type: type,
          count: risksByType[type].length
        })),
        risks_by_source: Object.keys(risksBySource).map(source => ({
          source,
          count: risksBySource[source].length
        }))
      },

      all_risks: risks,
      built_at: new Date().toISOString()
    }
  }
];

const items = $input.all();
const risks = items.map(item => item.json);

if (risks.length === 0) {
  return [
    {
      json: {
        no_risk_detected: true,
        sprint_health_score: 100,
        global_risk_level: "Faible",
        total_risks: 0,
        critical_risks: 0,
        high_risks: 0,
        medium_risks: 0,
        executive_summary: "Aucun risque significatif détecté. Le sprint peut rester en suivi standard.",
        analyzed_at: new Date().toISOString()
      }
    }
  ];
}

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function countBy(array, field) {
  const result = {};
  for (const item of array) {
    const key = clean(item[field]) || "Non qualifié";
    result[key] = (result[key] || 0) + 1;
  }
  return result;
}

function sortEntriesDesc(obj) {
  return Object.entries(obj).sort((a, b) => b[1] - a[1]);
}

const criticalRisks = risks.filter(r => r.risk_level === "Critique");
const highRisks = risks.filter(r => r.risk_level === "Élevé");
const mediumRisks = risks.filter(r => r.risk_level === "Moyen");

let sprintHealthScore = 100;

sprintHealthScore -= criticalRisks.length * 18;
sprintHealthScore -= highRisks.length * 10;
sprintHealthScore -= mediumRisks.length * 5;

const totalRiskScore = risks.reduce((sum, r) => sum + Number(r.risk_score || 0), 0);

if (totalRiskScore >= 300) sprintHealthScore -= 20;
else if (totalRiskScore >= 200) sprintHealthScore -= 12;
else if (totalRiskScore >= 100) sprintHealthScore -= 6;

if (sprintHealthScore < 0) sprintHealthScore = 0;

let globalRiskLevel = "Faible";
if (sprintHealthScore < 40) globalRiskLevel = "Critique";
else if (sprintHealthScore < 60) globalRiskLevel = "Élevé";
else if (sprintHealthScore < 80) globalRiskLevel = "Moyen";

const risksByType = countBy(risks, "risk_type");
const risksByAssignee = countBy(risks, "assignee");
const risksBySource = countBy(risks, "source");

const topRiskTypes = sortEntriesDesc(risksByType)
  .slice(0, 5)
  .map(([type, count]) => `${type}: ${count}`)
  .join(" | ");

const topAssignees = sortEntriesDesc(risksByAssignee)
  .slice(0, 5)
  .map(([person, count]) => `${person}: ${count}`)
  .join(" | ");

let executiveSummary = "";

if (globalRiskLevel === "Critique") {
  executiveSummary = `Le sprint est en zone critique avec ${risks.length} risque(s), dont ${criticalRisks.length} critique(s). Une décision d’arbitrage est nécessaire aujourd’hui.`;
} else if (globalRiskLevel === "Élevé") {
  executiveSummary = `Le sprint présente un niveau de risque élevé avec ${risks.length} risque(s). Les blocages principaux doivent être traités sous 24h.`;
} else if (globalRiskLevel === "Moyen") {
  executiveSummary = `Le sprint reste maîtrisable mais nécessite une surveillance renforcée. ${risks.length} risque(s) doivent être suivis.`;
} else {
  executiveSummary = `Le sprint est globalement sain malgré ${risks.length} risque(s) mineur(s).`;
}

return risks.map(risk => ({
  json: {
    ...risk,
    sprint_health_score: sprintHealthScore,
    global_risk_level: globalRiskLevel,
    total_risks: risks.length,
    critical_risks: criticalRisks.length,
    high_risks: highRisks.length,
    medium_risks: mediumRisks.length,
    total_risk_score: totalRiskScore,
    top_risk_types: topRiskTypes,
    top_assignees: topAssignees,
    top_sources: sortEntriesDesc(risksBySource).map(([s, c]) => `${s}: ${c}`).join(" | "),
    executive_summary: executiveSummary,
    analyzed_at: new Date().toISOString()
  }
}));

const items = $input.all();
const today = new Date();

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function parseDate(value) {
  if (!value) return null;
  const date = new Date(value);
  return isNaN(date.getTime()) ? null : date;
}

function daysBetween(date1, date2) {
  if (!date1 || !date2) return null;
  return Math.floor((date2 - date1) / (1000 * 60 * 60 * 24));
}

function isDone(status) {
  const value = clean(status).toLowerCase();
  return (
    value.includes("done") ||
    value.includes("termin") ||
    value.includes("closed") ||
    value.includes("resolved") ||
    value.includes("livré") ||
    value.includes("livree") ||
    value.includes("livrée")
  );
}

function priorityScore(priority) {
  const value = clean(priority).toLowerCase();

  if (value.includes("critique") || value.includes("critical") || value.includes("highest")) return 20;
  if (value.includes("haute") || value.includes("high")) return 15;
  if (value.includes("moyenne") || value.includes("medium")) return 8;
  if (value.includes("basse") || value.includes("low")) return 3;

  return 5;
}

function getRiskLevel(score) {
  if (score >= 80) return "Critique";
  if (score >= 55) return "Élevé";
  if (score >= 30) return "Moyen";
  return "Faible";
}

function detectMainRiskType(reasons) {
  const text = reasons.join(" ").toLowerCase();

  if (text.includes("review") || text.includes("validation")) return "Validation";
  if (text.includes("ci/cd") || text.includes("technique")) return "Technique";
  if (text.includes("deadline") || text.includes("retard") || text.includes("sprint")) return "Planning";
  if (text.includes("surchargé") || text.includes("surcharge")) return "Charge équipe";
  if (text.includes("responsable")) return "Organisation";
  if (text.includes("bloqué") || text.includes("bloquee")) return "Blocage";

  return "Risque delivery";
}

function buildDecision(riskLevel, item) {
  const assignee = clean(item.assignee) || "responsable non identifié";

  if (riskLevel === "Critique") {
    return `Décision immédiate requise : arbitrer aujourd’hui, contacter ${assignee}, activer un backup si nécessaire et fixer une heure limite de résolution.`;
  }

  if (riskLevel === "Élevé") {
    return `Action rapide sous 24h : demander un point de blocage à ${assignee}, confirmer la cause et définir une action de déblocage.`;
  }

  if (riskLevel === "Moyen") {
    return `Surveillance renforcée : suivre l’évolution de la tâche et demander une mise à jour au prochain point projet.`;
  }

  return "Suivi normal.";
}

const risks = [];

for (const item of items) {
  const data = item.json;

  const status = clean(data.status);
  const title = clean(data.title);
  const externalId = clean(data.external_id || data.task_id);

  let score = 0;
  const reasons = [];

  const createdAt = parseDate(data.created_at);
  const updatedAt = parseDate(data.updated_at);
  const dueDate = parseDate(data.due_date);
  const sprintEndDate = parseDate(data.sprint_end_date);

  const ageDays = createdAt ? daysBetween(createdAt, today) : null;
  const inactiveDays = updatedAt ? daysBetween(updatedAt, today) : null;
  const remainingDays = sprintEndDate ? daysBetween(today, sprintEndDate) : null;

  if (data.blocked === true) {
    score += 30;
    reasons.push("Élément marqué comme bloqué");
  }

  if (clean(data.review_status).toLowerCase().includes("attente")) {
    score += 20;
    reasons.push("Review ou validation en attente");
  }

  if (clean(data.ci_status).toLowerCase() === "failed") {
    score += 25;
    reasons.push("CI/CD échouée");
  }

  if (dueDate && dueDate < today && !isDone(status)) {
    score += 25;
    reasons.push("Deadline dépassée");
  }

  if (inactiveDays !== null && inactiveDays >= 3 && !isDone(status)) {
    score += 10;
    reasons.push(`Aucune mise à jour depuis ${inactiveDays} jours`);
  }

  if (ageDays !== null && ageDays >= 5 && !isDone(status)) {
    score += 10;
    reasons.push(`Tâche ouverte depuis ${ageDays} jours`);
  }

  if (!clean(data.assignee)) {
    score += 15;
    reasons.push("Aucun responsable assigné");
  }

  // Temps restant dans le sprint
  if (remainingDays !== null && remainingDays <= 1 && !isDone(status)) {
    score += 20;
    reasons.push("Fin de sprint imminente");
  } else if (remainingDays !== null && remainingDays <= 3 && !isDone(status)) {
    score += 12;
    reasons.push("Moins de 3 jours restants dans le sprint");
  }

  // Charge développeur
  if (data.developer_overloaded === true) {
    score += 20;
    reasons.push("Développeur surchargé");
  }

  score += priorityScore(data.priority);

  if (score < 30) continue;

  const riskLevel = getRiskLevel(score);
  const riskType = detectMainRiskType(reasons);
  const decision = buildDecision(riskLevel, data);

  const alertKey = [
    data.source || "airtable",
    externalId || title,
    riskType,
    riskLevel
  ].join("-").replace(/\s+/g, "_").toLowerCase();

  risks.push({
    json: {
      alert_key: alertKey,

      source: data.source || "airtable",
      type: data.type || "task",
      external_id: externalId,
      task_id: data.task_id || externalId,
      title,

      status,
      assignee: data.assignee || "",
      assignee_email: data.assignee_email || "",
      priority: data.priority || "",
      sprint: data.sprint || "",

      risk_score: score,
      risk_level: riskLevel,
      risk_type: riskType,

      reasons_detected: reasons.join(" | "),
      decision_required: decision,

      blocker_type: data.blocker_type || riskType,
      pr_blocker_summary: "",

      linked_pr_count: 0,
      linked_prs: [],

      remaining_sprint_days: remainingDays,

      developer_load: data.developer_load || {},
      developer_overloaded: data.developer_overloaded === true,
      developer_load_summary: data.developer_load_summary || "",

      source_url: data.source_url || "",
      detected_at: today.toISOString(),
      status_alert: "Ouverte",

      raw_context: data
    }
  });
}

return risks;

const items = $input.all();

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function normalizePriority(priority) {
  const value = clean(priority).toLowerCase();

  if (["critical", "critique", "urgent", "highest", "blocker"].some(v => value.includes(v))) return "Critique";
  if (["high", "haute", "major", "majeure"].some(v => value.includes(v))) return "Haute";
  if (["medium", "moyenne", "normal"].some(v => value.includes(v))) return "Moyenne";
  if (["low", "basse", "mineure"].some(v => value.includes(v))) return "Basse";

  return priority || "Non définie";
}

function daysSince(dateValue) {
  if (!dateValue) return null;
  const date = new Date(dateValue);
  if (isNaN(date.getTime())) return null;
  return Math.floor((Date.now() - date.getTime()) / (1000 * 60 * 60 * 24));
}

function detectBlocked(fields) {
  const text = [
    fields["État"],
    fields.Etat,
    fields.Status,
    fields.Statut,
    fields.Title,
    fields.Titre,
    fields.Description,
    fields.Blocker,
    fields.Blocage,
    fields.Labels
  ].join(" ").toLowerCase();

  return (
    text.includes("blocked") ||
    text.includes("bloqué") ||
    text.includes("bloquee") ||
    text.includes("bloquée") ||
    text.includes("en attente") ||
    text.includes("waiting") ||
    text.includes("validation")
  );
}

function detectBlockerType(fields) {
  const text = [
    fields["État"],
    fields.Etat,
    fields.Status,
    fields.Statut,
    fields.Title,
    fields.Titre,
    fields.Description,
    fields.Blocker,
    fields.Blocage,
    fields.Labels
  ].join(" ").toLowerCase();

  if (text.includes("review") || text.includes("validation") || text.includes("pr")) return "Validation";
  if (text.includes("bug") || text.includes("api") || text.includes("tech") || text.includes("ci")) return "Technique";
  if (text.includes("client") || text.includes("métier") || text.includes("fonctionnel")) return "Fonctionnel";
  if (text.includes("dépendance") || text.includes("dependency")) return "Dépendance";
  if (text.includes("absence") || text.includes("disponibilité")) return "Disponibilité";

  return "";
}

const clientContext = $("Set - Client Context").item?.json || {};
const normalized = [];

for (const item of items) {
  let records = [];

  if (Array.isArray(item.json.records)) {
    records = item.json.records;
  } else if (item.json.id && item.json.fields) {
    records = [item.json];
  } else if (Array.isArray(item.json)) {
    records = item.json;
  }

  for (const record of records) {
    const fields = record.fields || record || {};

    const externalId = clean(fields.TaskID || fields.ID || fields["ID tâche"] || record.id);
    const title = clean(
  fields.Title ||
  fields.Titre ||
  fields["Titre US"] ||
  fields.Name ||
  fields.Nom ||
  fields.Summary ||
  fields.Description
);
    const status = clean(fields.Status || fields["État"] || fields.Etat || fields.Statut);
    const assignee = clean(
  fields.Assignee ||
  fields["Assignée à"] ||
  fields.Responsable ||
  fields["Responsable déblocage"] ||
  fields.Owner
);
    const assigneeEmail = clean(fields.AssigneeEmail || fields.Email || fields["Email responsable"]);

    const priority = normalizePriority(fields.Priority || fields.Priorité);
    const sprint = clean(fields.Sprint);
    const dueDate = clean(fields.DueDate || fields.Deadline || fields["Date limite"]);
    const createdAt = clean(fields.CreatedAt || fields["Date création"] || record.createdTime);
    const updatedAt = clean(fields.UpdatedAt || fields.LastModified || fields["Dernière modification"]);
    const sourceUrl = clean(fields.URL || fields.Link || fields.Lien);

    const blocked = detectBlocked(fields);
    const blockerType = detectBlockerType(fields);

    normalized.push({
      json: {
        job_id: clientContext.job_id || `job_${Date.now()}`,
        client_id: clientContext.client_id || "client_airtable_001",
        client_name: clientContext.client_name || "Client Airtable",

        source: "airtable",
        source_method: clientContext.source_method || "airtable_http",
        type: "task",

        airtable_record_id: record.id || "",

        external_id: externalId,
        task_id: externalId,
        title,

        status,
        status_category: status,
        assignee,
        assignee_email: assigneeEmail,
        reporter: "",

        priority,
        sprint,
        created_at: createdAt,
        updated_at: updatedAt,
        due_date: dueDate,
        age_days: daysSince(createdAt),

        sprint_start_date: clientContext.sprint_start_date || "",
        sprint_end_date: clientContext.sprint_end_date || "",

        labels: fields.Labels || [],
        blocked,
        blocker_type: blockerType,

        review_status: clean(fields.ReviewStatus || fields["Statut review"] || ""),
        ci_status: clean(fields.CIStatus || fields["Statut CI"] || ""),
        linked_pr: clean(fields.LinkedPR || fields["Lien PR"] || ""),

        raw_source: "airtable",
        source_url: sourceUrl,

        raw_context: fields,
        normalized_at: new Date().toISOString()
      }
    });
  }
}

if (normalized.length === 0) {
  return [
    {
      json: {
        source: "airtable",
        source_method: clientContext.source_method || "airtable_http",
        client_id: clientContext.client_id || "client_airtable_001",
        level: "warning",
        type: "empty_airtable_result",
        message: "Aucune ligne Airtable exploitable trouvée. Vérifier le filtre, le nom de table, les colonnes ou la réponse HTTP.",
        raw_input_sample: items[0]?.json || {},
        created_at: new Date().toISOString()
      }
    }
  ];
}

return normalized;

