const items = $input.all();
const data = items.map(item => item.json);

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function isDone(status) {
  const value = clean(status).toLowerCase();
  return value.includes("done") || value.includes("termin") || value.includes("closed") || value.includes("livré");
}

const loadByAssignee = {};

for (const task of data) {
  const assignee = clean(task.assignee) || "Non assigné";

  if (!loadByAssignee[assignee]) {
    loadByAssignee[assignee] = {
      total_open_tasks: 0,
      blocked_tasks: 0,
      high_priority_tasks: 0
    };
  }

  if (!isDone(task.status)) {
    loadByAssignee[assignee].total_open_tasks += 1;
  }

  if (task.blocked === true) {
    loadByAssignee[assignee].blocked_tasks += 1;
  }

  const p = clean(task.priority).toLowerCase();
  if (p.includes("critique") || p.includes("haute") || p.includes("high") || p.includes("critical")) {
    loadByAssignee[assignee].high_priority_tasks += 1;
  }
}

return data.map(task => {
  const assignee = clean(task.assignee) || "Non assigné";
  const load = loadByAssignee[assignee];

  const overloaded =
    load.total_open_tasks >= 6 ||
    load.blocked_tasks >= 3 ||
    load.high_priority_tasks >= 4;

  return {
    json: {
      ...task,
      developer_load: load,
      developer_overloaded: overloaded,
      developer_load_summary: `${assignee} a ${load.total_open_tasks} tâche(s) ouvertes, ${load.blocked_tasks} bloquée(s), ${load.high_priority_tasks} prioritaire(s).`
    }
  };
});

