const items = $input.all();

const current = $("Set - Current Sprint Health Context").first().json;
const previous = items[0]?.json || null;

const currentScore = Number(
  current.current_sprint_health_score ||
  current.sprint_health_score ||
  0
);

const hasPrevious =
  previous &&
  previous.is_first_measure !== true &&
  previous.sprint_health_score !== null &&
  previous.sprint_health_score !== undefined;

const previousScore = hasPrevious
  ? Number(previous.sprint_health_score || 0)
  : null;

let trend = "premiere_mesure";
let trend_label = "Première mesure";
let trend_delta = null;
let trend_message = "Première mesure enregistrée. La tendance sera calculée à partir de la prochaine analyse.";

if (hasPrevious) {
  trend_delta = currentScore - previousScore;

  if (trend_delta <= -10) {
    trend = "degradation";
    trend_label = "Dégradation";
    trend_message = `Le sprint se dégrade : ${trend_delta} points par rapport à la précédente mesure.`;
  } else if (trend_delta >= 10) {
    trend = "amelioration";
    trend_label = "Amélioration";
    trend_message = `Le sprint s’améliore : +${trend_delta} points par rapport à la précédente mesure.`;
  } else {
    trend = "stable";
    trend_label = "Stable";
    trend_message = `Le sprint est globalement stable : ${trend_delta >= 0 ? "+" : ""}${trend_delta} point(s).`;
  }
}

return [
  {
    json: {
      ...current,

      previous_sprint_health_score: previousScore,
      current_sprint_health_score: currentScore,

      trend,
      trend_label,
      trend_delta,
      trend_message,

      previous_global_risk_level: hasPrevious ? previous.global_risk_level : null,
      previous_total_risks: hasPrevious ? previous.total_risks : null,
      previous_critical_risks: hasPrevious ? previous.critical_risks : null,
      previous_analyzed_at: hasPrevious ? previous.analyzed_at : null,

      is_first_measure: !hasPrevious,
      trend_calculated_at: new Date().toISOString()
    }
  }
];

const items = $input.all();

if (items.length === 0) {
  return [
    {
      json: {
        sprint_health_score: 100,
        global_risk_level: "Faible",
        total_risks: 0,
        critical_risks: 0,
        high_risks: 0,
        medium_risks: 0,
        total_risk_score: 0,
        top_risk_types: "",
        top_assignees: "",
        executive_summary: "Aucun risque détecté.",
        analyzed_at: new Date().toISOString()
      }
    }
  ];
}

const first = items[0].json;

return [
  {
    json: {
      client_id: $("Set - Client Context").first().json.client_id || null,
      client_name: $("Set - Client Context").first().json.client_name || null,

      sprint: first.sprint || $("Set - Client Context").first().json.current_sprint || "Sprint courant",
      sprint_start_date: $("Set - Client Context").first().json.sprint_start_date || null,
      sprint_end_date: $("Set - Client Context").first().json.sprint_end_date || null,

      sprint_health_score: first.sprint_health_score || 0,
      global_risk_level: first.global_risk_level || "",
      total_risks: first.total_risks || 0,
      critical_risks: first.critical_risks || 0,
      high_risks: first.high_risks || 0,
      medium_risks: first.medium_risks || 0,
      total_risk_score: first.total_risk_score || 0,
      top_risk_types: first.top_risk_types || "",
      top_assignees: first.top_assignees || "",
      executive_summary: first.executive_summary || "",

      raw_context: {
        risks_count: items.length,
        sample_risks: items.slice(0, 10).map(i => i.json)
      },

      analyzed_at: new Date().toISOString()
    }
  }
];
